const payload = $json.body ?? $json;
const data = payload.data ?? payload;
const key = data.key ?? payload.key ?? {};
const message = data.message ?? payload.message ?? {};
const text = message.conversation
  ?? message.extendedTextMessage?.text
  ?? message.imageMessage?.caption
  ?? message.videoMessage?.caption
  ?? data.messageText
  ?? payload.messageText
  ?? '';
const remoteJid = key.remoteJid ?? data.remoteJid ?? payload.remoteJid ?? '';
const phoneDigits = remoteJid.split('@')[0].replace(/\D/g, '');
const phone = phoneDigits ? `+${phoneDigits}` : '';
const messageType = Object.keys(message)[0] ?? data.messageType ?? 'text';
const fromMe = Boolean(key.fromMe ?? data.fromMe ?? payload.fromMe ?? false);
const instance = payload.instance ?? data.instance ?? $env.EVOLUTION_INSTANCE_NAME;

return [{
  json: {
    raw_event: payload,
    n8n_execution_id: $execution.id,
    received_at: new Date().toISOString(),
    evolution_instance_id: instance,
    whatsapp_remote_jid: remoteJid,
    evolution_message_id: key.id ?? data.id ?? payload.id ?? null,
    patient_phone_e164: phone,
    patient_name: data.pushName ?? payload.pushName ?? data.contact?.name ?? null,
    message_text: text.trim(),
    message_type: messageType,
    media_url: data.mediaUrl ?? payload.mediaUrl ?? null,
    media_mime_type: data.mimetype ?? payload.mimetype ?? null,
    sent_at: data.messageTimestamp
      ? new Date(Number(data.messageTimestamp) * 1000).toISOString()
      : new Date().toISOString(),
    is_from_bot: fromMe,
    should_process: !fromMe && remoteJid !== '' && (text.trim() !== '' || data.mediaUrl || payload.mediaUrl)
  }
}];

const incoming = $('Normalize Incoming Message').first().json;
const result = $input.first().json;
const rows = Array.isArray(result)
  ? result
  : (Array.isArray(result.data) ? result.data : (result.id ? [result] : []));
const conversation = rows[0] ?? null;
return [{ json: { ...incoming, conversation, has_conversation: Boolean(conversation?.id) } }];

