const incoming = $('Resolve Conversation State').first().json;
const result = $input.first().json;
const row = Array.isArray(result) ? result[0] : result;
return [{ json: { ...incoming, conversation: row, conversation_id: row.id, conversation_status: row.status, conversation_intent: row.intent } }];

let current;
try {
  current = $('Use Existing Conversation').first().json;
} catch (error) {
  current = $('Use Created Conversation').first().json;
}
const result = $input.first().json;
const rawRows = Array.isArray(result)
  ? result
  : (Array.isArray(result.data) ? result.data : (result.sender ? [result] : []));
const historyRows = rawRows.reverse();
const historyText = historyRows
  .map((m) => `${m.sender}/${m.direction}: ${m.body ?? ''}`)
  .filter((line) => line.trim().length > 0)
  .join('\n');
const clinicContext = `Clinic: Clinica Sorriso Feliz\nRole: You are a WhatsApp assistant for a dental clinic. Be concise, polite, and helpful in Brazilian Portuguese. Do not diagnose. For pain, emergencies, medical risk, complaints, pricing negotiation, or explicit request for a person, hand off to a human.`;
return [{
  json: {
    ...current,
    history: historyRows,
    memory_context: `${clinicContext}\n\nPrevious conversation:\n${historyText || 'No previous messages.'}\n\nCurrent patient message:\n${current.message_text}`
  }
}];

parameters.jsonBody:
={{ {
  contents: [{
    role: 'user',
    parts: [{ text: `Classify this dental clinic WhatsApp conversation. Return ONLY valid JSON with keys: intent, confidence, needs_human, handoff_reason, summary. Allowed intents: AGENDAMENTO, ORCAMENTO, DUVIDA, HUMANO. needs_human must be true for explicit human request, emergency symptoms, complaint, sensitive medical issue, uncertain answer, or anything outside clinic assistant scope.\n\n${$json.memory_context}` }]
  }],
  generationConfig: {
    temperature: 0.1,
    responseMimeType: 'application/json'
  }
} }}

