const current = $('Build Memory Context').first().json;
const response = $input.first().json;
const text = response.candidates?.[0]?.content?.parts?.[0]?.text ?? '{}';
let parsed;
try {
  parsed = JSON.parse(text);
} catch (error) {
  parsed = { intent: 'HUMANO', confidence: 0, needs_human: true, handoff_reason: 'Falha ao interpretar classificacao do Gemini.', summary: null };
}
const allowed = ['AGENDAMENTO', 'ORCAMENTO', 'DUVIDA', 'HUMANO'];
const intent = allowed.includes(parsed.intent) ? parsed.intent : 'HUMANO';
const alreadyWaitingHuman = current.conversation_status === 'aguardando_humano';
const needsHuman = Boolean(alreadyWaitingHuman || parsed.needs_human || intent === 'HUMANO');
return [{
  json: {
    ...current,
    classification: parsed,
    intent: alreadyWaitingHuman ? 'HUMANO' : intent,
    intent_confidence: Math.max(0, Math.min(1, Number(parsed.confidence ?? 0))),
    needs_human: needsHuman,
    handoff_reason: alreadyWaitingHuman ? 'Conversa ja esta aguardando atendimento humano.' : (parsed.handoff_reason ?? (needsHuman ? 'Encaminhamento solicitado por regra de atendimento.' : null)),
    conversation_summary: parsed.summary ?? null,
    gemini_classification_raw: response,
    gemini_prompt_tokens: response.usageMetadata?.promptTokenCount ?? null,
    gemini_completion_tokens: response.usageMetadata?.candidatesTokenCount ?? null,
    gemini_total_tokens: response.usageMetadata?.totalTokenCount ?? null
  }
}];

