  handoff_reason: $json.needs_human ? $json.handoff_reason : null
} }}

={{ {
  contents: [{
    role: 'user',
    parts: [{ text: `Generate the next WhatsApp reply in Brazilian Portuguese for Clinica Sorriso Feliz. Be concise, warm, and helpful. Do not invent prices, medical diagnosis, or appointment availability. If scheduling is requested, ask for preferred day/time and patient name if missing. If budget/price is requested, explain that the team can guide after evaluation.\n\nConversation context:\n${$json.memory_context}\n\nClassified intent: ${$json.intent}` }]
