const current = $('Restore Context After Status Update').first().json;
const response = $input.first().json;
const aiText = response.candidates?.[0]?.content?.parts?.map((p) => p.text).join('\n').trim() || 'Obrigado pelo contato. A equipe da Clinica Sorriso Feliz vai te ajudar em instantes.';
return [{
  json: {
    ...current,
    ai_response_text: aiText,
    gemini_response_raw: response,
    gemini_prompt_tokens: response.usageMetadata?.promptTokenCount ?? current.gemini_prompt_tokens,
    gemini_completion_tokens: response.usageMetadata?.candidatesTokenCount ?? current.gemini_completion_tokens,
    gemini_total_tokens: response.usageMetadata?.totalTokenCount ?? current.gemini_total_tokens
  }
}];

const current = $('Parse AI Response').all().length ? $('Parse AI Response').first().json : $('Build Human Handoff Response').first().json;
const inserted = $input.first().json;
const outbound = Array.isArray(inserted) ? inserted[0] : inserted;
return [{ json: { ...current, outbound_message_id: outbound.id } }];

const current = $('Restore Context After Outbound Insert').first().json;
const evolutionResponse = $input.first().json;
return [{ json: { ...current, evolution_send_response: evolutionResponse } }];

